typedef enum SDL_AppResult
{
 SDL_APP_CONTINUE, /**< تعاد هذه القيمة من رد نداء في نظام main callbacks لتطلب من SDL متابعة تشغيل التطبيق واستمرار الحلقة الرئيسية. */
 SDL_APP_SUCCESS, /**< تعاد هذه القيمة من رد نداء في نظام main callbacks لتطلب من SDL إنهاء الحلقة وإغلاق التطبيق بحالة نجاح. */
 SDL_APP_FAILURE  /**< تعاد هذه القيمة من رد نداء في نظام main callbacks لتطلب من SDL إنهاء الحلقة وإغلاق التطبيق بحالة فشل. */
} SDL_AppResult;

