typedef enum SDL_AssertState
{
 SDL_ASSERTION_RETRY, /**< تشير هذه القيمة إلى أن SDL تعيد تنفيذ عبارة التأكيد الحالية فورًا بدل متابعة التنفيذ أو إنهاء البرنامج. */
 SDL_ASSERTION_BREAK, /**< تشير هذه القيمة إلى أن SDL تطلب من المصحح التوقف عند عبارة التأكيد الحالية عبر نقطة توقف. */
 SDL_ASSERTION_ABORT, /**< تشير هذه القيمة إلى أن SDL تنهي البرنامج عند معالجة عبارة التأكيد الحالية. */
 SDL_ASSERTION_IGNORE, /**< تشير هذه القيمة إلى أن SDL تتجاهل عبارة التأكيد الحالية مرة واحدة ثم تتابع التنفيذ. */
 SDL_ASSERTION_ALWAYS_IGNORE  /**< تشير هذه القيمة إلى أن SDL تتجاهل عبارة التأكيد الحالية في المرات اللاحقة أيضًا ولا تعيد طرحها من جديد. */
} SDL_AssertState;

typedef enum SDL_AsyncIOResult
{
 SDL_ASYNCIO_COMPLETE, /**< تعاد هذه القيمة عندما يكتمل طلب SDL_AsyncIO بنجاح، وعند ظهورها يفهم التطبيق أن العملية انتهت من دون خطأ إضافي. */
 SDL_ASYNCIO_FAILURE, /**< تعاد هذه القيمة عندما يفشل طلب SDL_AsyncIO، وعند ظهورها يجب فحص SDL_GetError() لمعرفة سبب الفشل قبل متابعة المعالجة. */
 SDL_ASYNCIO_CANCELED  /**< تعاد هذه القيمة عندما يُلغى طلب SDL_AsyncIO قبل اكتماله، وعند ظهورها لا تكون العملية قد وصلت إلى نتيجتها الطبيعية. */
} SDL_AsyncIOResult;

typedef enum SDL_AsyncIOTaskType
{
 SDL_ASYNCIO_TASK_READ, /**< تشير هذه القيمة إلى أن مهمة SDL_AsyncIO الحالية تنفذ قراءة من المصدر المرتبط، لذلك يعاملها النظام كعملية إدخال بيانات. */
 SDL_ASYNCIO_TASK_WRITE, /**< تشير هذه القيمة إلى أن مهمة SDL_AsyncIO الحالية تنفذ كتابة إلى الوجهة المرتبطة، لذلك يعاملها النظام كعملية إخراج بيانات. */
 SDL_ASYNCIO_TASK_CLOSE  /**< تشير هذه القيمة إلى أن مهمة SDL_AsyncIO الحالية تنفذ إغلاقًا للمورد أو المجرى المرتبط بعد اكتمال العمل عليه. */
} SDL_AsyncIOTaskType;

typedef enum SDL_AudioFormat
{
 SDL_AUDIO_UNKNOWN = 0x0000u, /**< تشير هذه القيمة إلى أن تنسيق الصوت غير محدد بعد، وتستخدمها SDL عندما لا تملك صيغة عينات صالحة يمكن الاعتماد عليها في هذا الموضع. */
 SDL_AUDIO_U8 = 0x0008u, /**< تشير هذه القيمة إلى عينات 8 بت غير موقعة داخل الحقل format في SDL_AudioSpec ومسارات الصوت، ويقرأها SDL لاختيار هذا السلوك أو هذه الحالة. */
 /* SDL_DEFINE_AUDIO_FORMAT(0, 0, 0, 8), */
 SDL_AUDIO_S8 = 0x8008u, /**< تشير هذه القيمة إلى عينات 8 بت موقعة داخل الحقل format في SDL_AudioSpec ومسارات الصوت، ويقرأها SDL لاختيار هذا السلوك أو هذه الحالة. */
 /* SDL_DEFINE_AUDIO_FORMAT(1, 0, 0, 8), */
 SDL_AUDIO_S16LE = 0x8010u, /**< تشير هذه القيمة إلى عينات 16 بت موقعة بترتيب بايتات صغير الطرفية داخل الحقل format في SDL_AudioSpec ومسارات الصوت، ويقرأها SDL لاختيار هذا السلوك أو هذه الحالة. */
 /* SDL_DEFINE_AUDIO_FORMAT(1, 0, 0, 16), */
 SDL_AUDIO_S16BE = 0x9010u, /**< تشير هذه القيمة إلى عينات 16 بت موقعة بترتيب بايتات كبير الطرفية داخل الحقل format في SDL_AudioSpec ومسارات الصوت، ويقرأها SDL لاختيار هذا السلوك أو هذه الحالة. */
 /* SDL_DEFINE_AUDIO_FORMAT(1, 1, 0, 16), */
 SDL_AUDIO_S32LE = 0x8020u, /**< تشير هذه القيمة إلى عينات 32 بت صحيحة بترتيب بايتات صغير الطرفية داخل الحقل format في SDL_AudioSpec ومسارات الصوت، ويقرأها SDL لاختيار هذا السلوك أو هذه الحالة. */
 /* SDL_DEFINE_AUDIO_FORMAT(1, 0, 0, 32), */
 SDL_AUDIO_S32BE = 0x9020u, /**< تشير هذه القيمة إلى عينات 32 بت صحيحة بترتيب بايتات كبير الطرفية داخل الحقل format في SDL_AudioSpec ومسارات الصوت، ويقرأها SDL لاختيار هذا السلوك أو هذه الحالة. */
 /* SDL_DEFINE_AUDIO_FORMAT(1, 1, 0, 32), */
 SDL_AUDIO_F32LE = 0x8120u, /**< تشير هذه القيمة إلى عينات 32 بت عائمة بترتيب بايتات صغير الطرفية داخل الحقل format في SDL_AudioSpec ومسارات الصوت، ويقرأها SDL لاختيار هذا السلوك أو هذه الحالة. */
 /* SDL_DEFINE_AUDIO_FORMAT(1, 0, 1, 32), */
 SDL_AUDIO_F32BE = 0x9120u, /**< تشير هذه القيمة إلى عينات 32 بت عائمة بترتيب بايتات كبير الطرفية داخل الحقل format في SDL_AudioSpec ومسارات الصوت، ويقرأها SDL لاختيار هذا السلوك أو هذه الحالة. */
 /* SDL_DEFINE_AUDIO_FORMAT(1, 1, 1, 32), */

 /* These represent the current system's byteorder. */
 #if SDL_BYTEORDER == SDL_LIL_ENDIAN
 SDL_AUDIO_S16 = SDL_AUDIO_S16LE, /**< تشير هذه القيمة إلى S16، وتُستخدم داخل الحقل format في SDL_AudioSpec ومسارات الصوت ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
 SDL_AUDIO_S32 = SDL_AUDIO_S32LE, /**< تشير هذه القيمة إلى S32، وتُستخدم داخل الحقل format في SDL_AudioSpec ومسارات الصوت ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
 SDL_AUDIO_F32 = SDL_AUDIO_F32LE /**< تشير هذه القيمة إلى F32، وتُستخدم داخل الحقل format في SDL_AudioSpec ومسارات الصوت ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
 #else
 SDL_AUDIO_S16 = SDL_AUDIO_S16BE, /**< تشير هذه القيمة إلى S16، وتُستخدم داخل الحقل format في SDL_AudioSpec ومسارات الصوت ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
 SDL_AUDIO_S32 = SDL_AUDIO_S32BE, /**< تشير هذه القيمة إلى S32، وتُستخدم داخل الحقل format في SDL_AudioSpec ومسارات الصوت ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
 SDL_AUDIO_F32 = SDL_AUDIO_F32BE /**< تشير هذه القيمة إلى F32، وتُستخدم داخل الحقل format في SDL_AudioSpec ومسارات الصوت ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
 #endif
} SDL_AudioFormat;

