typedef enum SDL_Capitalization
{
 SDL_CAPITALIZE_NONE, /**< تشير هذه القيمة إلى أن SDL لا تطبق أي رسملة تلقائية على النص المدخل في هذا المسار. */
 SDL_CAPITALIZE_SENTENCES, /**< تشير هذه القيمة إلى أن SDL ترسمل أول حرف من كل جملة عند تطبيق سياسة الرسملة التلقائية. */
 SDL_CAPITALIZE_WORDS, /**< تشير هذه القيمة إلى أن SDL ترسمل أول حرف من كل كلمة عند تطبيق سياسة الرسملة التلقائية. */
 SDL_CAPITALIZE_LETTERS  /**< تشير هذه القيمة إلى أن SDL ترسمل جميع الحروف عند تطبيق سياسة الرسملة التلقائية. */
} SDL_Capitalization;

typedef enum SDL_ChromaLocation
{
 SDL_CHROMA_LOCATION_NONE = 0, /**< تشير هذه القيمة إلى أن SDL يتعامل مع البيانات على أنها RGB من دون عينات لون فرعي منفصلة. */
 SDL_CHROMA_LOCATION_LEFT = 1, /**< تشير هذه القيمة إلى أن SDL يقرأ عينات اللون الفرعي على أنها مزاحة نحو الجهة اليسرى وفق التموضع القياسي لهذا النمط. */
 SDL_CHROMA_LOCATION_CENTER = 2, /**< تشير هذه القيمة إلى أن SDL يقرأ عينات اللون الفرعي من مركز المربع المرجعي المرتبط بها. */
 SDL_CHROMA_LOCATION_TOPLEFT = 3  /**< تشير هذه القيمة إلى أن SDL يقرأ عينات اللون الفرعي من موضع الزاوية العليا اليسرى للمجموعة المرجعية. */
} SDL_ChromaLocation;

typedef enum SDL_ColorRange
{
 SDL_COLOR_RANGE_UNKNOWN = 0, /**< تشير هذه القيمة إلى UNKNOWN، وتُستخدم داخل وصف مدى الإشارة اللونية في SDL ليعرف SDL هذا الاختيار أو هذه الحالة عند القراءة أو المقارنة. */
 SDL_COLOR_RANGE_LIMITED = 1, /**< تشير هذه القيمة إلى أن SDL يتعامل مع الإشارة اللونية على أنها ضمن مدى محدود، لذلك لا تستخدم القنوات كامل المجال العددي المتاح. */
 SDL_COLOR_RANGE_FULL = 2  /**< تشير هذه القيمة إلى أن SDL يتعامل مع الإشارة اللونية على أنها ضمن مدى كامل، لذلك تستفيد القنوات من المجال العددي الكامل المتاح. */
} SDL_ColorRange;

typedef enum SDL_ColorType
