typedef enum SDL_DisplayOrientation
{
 SDL_ORIENTATION_UNKNOWN, /**< تشير هذه القيمة إلى أن SDL لم تستطع تحديد اتجاه الشاشة الحالي، لذلك لا يجوز افتراض وضع عرض محدد من خلالها. */
